/**
 * 修改数据点配置处理器
 */

import type {
  ActionHandler,
  ActionResult,
  EventContext,
  ChangeDataPointParams,
} from '../events.types'
import { showSchemaFormDialog } from '../dialog-atom'
import { createAPI } from '@airiot/client'
import _ from 'lodash'
import { showResultMessage } from './utils'

/**
 * 更新资产数据点
 */
async function updateRecordDataPoint(
  dp: any,
  pointValue: any
): Promise<void> {
  const recordDataPoint = dp.recordDataPoint
  const tableId = recordDataPoint?.tableId
  const tableDataId = recordDataPoint?.tableDataId
  const tagId = recordDataPoint?.tagId

  if (!tableDataId || !tableId) {
    throw new Error('资产数据点缺少 tableId 或 tableDataId')
  }

  // 查询资产数据
  const dataApi = createAPI({ name: `core/t/${tableId}/d` })
  const { items } = await dataApi.query(
    { fields: ['device'] },
    { where: { id: { '$in': [tableDataId] } } }
  )

  const oldData = items?.[0]?._settings
  if (!oldData) {
    throw new Error('找不到资产数据')
  }

  // 更新数据点值
  let hasTag = false
  oldData.device?.tags?.forEach((tag: any) => {
    if (tag.id === tagId) {
      _.set(tag, dp.key, pointValue)
      hasTag = true
    }
  })

  if (!hasTag) {
    throw new Error(`资产数据中找不到数据点 ${tagId}`)
  }

  // 准备保存数据
  oldData.tableInfo = { id: tableId }
  oldData.tableData = { id: tableDataId }
  oldData.id = tableDataId

  // 保存到 record
  const recordApi = createAPI({ name: 'core/t' })
  await recordApi.fetch(`/record`, {
    method: 'POST',
    noMessage: true,
    body: JSON.stringify(oldData),
  })
}

/**
 * 更新模型数据点
 */
async function updateTableDataPoint(
  dp: any,
  pointValue: any
): Promise<void> {
  const tableDataPoint = dp.tableDataPoint
  const tableId = tableDataPoint?.tableId
  const tagId = tableDataPoint?.tagId

  if (!tableId) {
    throw new Error('模型数据点缺少 tableId')
  }

  // 查询模型数据
  const schemaApi = createAPI({ name: 'core/t/schema' })
  const { items } = await schemaApi.query(
    { fields: ['device'] },
    { where: { id: { '$in': [tableId] } } }
  )

  const oldData = items?.[0]
  if (!oldData) {
    throw new Error('找不到模型数据')
  }

  // 更新数据点值
  let hasTag = false
  oldData.device?.tags?.forEach((tag: any) => {
    if (tag.id === tagId) {
      _.set(tag, dp.key, pointValue)
      hasTag = true
    }
  })

  if (!hasTag) {
    throw new Error(`模型数据中找不到数据点 ${tagId}`)
  }

  // 保存到 schema
  const updateApi = createAPI({ name: 'core/t' })
  await updateApi.fetch(`/schema/${tableId}`, {
    method: 'PATCH',
    noMessage: true,
    body: JSON.stringify(oldData),
  })
}

export const changeDataPointHandler: ActionHandler = async (
  params: ChangeDataPointParams,
  _context: EventContext
): Promise<ActionResult> => {
  try {
    const { dataPointMulti, showForm } = params

    if (!dataPointMulti || dataPointMulti.length === 0) {
      throw new Error('缺少 dataPointMulti 参数')
    }

    // 如果是弹出表单模式
    if (showForm) {
      // 获取当前的数据点值
      const initialValues: any = {}

      // 查询每个数据点的当前值
      for (const dp of dataPointMulti) {
        if (dp.recordDataPoint) {
          const { tableId, tableDataId, tagId } = dp.recordDataPoint

          if (tableDataId && tableId) {
            const dataApi = createAPI({ name: `core/t/${tableId}/d` })
            const { items } = await dataApi.query(
              { fields: ['device'] },
              { where: { id: { '$in': [tableDataId] } } }
            )

            const oldData = items?.[0]?._settings
            const tag = oldData?.device?.tags?.find((t: any) => t.id === tagId)

            if (tag) {
              initialValues[dp.key] = _.get(tag, dp.key)
            }
          }
        } else if (dp.tableDataPoint) {
          const { tableId, tagId } = dp.tableDataPoint

          if (tableId) {
            const schemaApi = createAPI({ name: 'core/t/schema' })
            const { items } = await schemaApi.query(
              { fields: ['device'] },
              { where: { id: { '$in': [tableId] } } }
            )

            const oldData = items?.[0]
            const tag = oldData?.device?.tags?.find((t: any) => t.id === tagId)
            if (tag) {
              initialValues[dp.key] = _.get(tag, dp.key)
            }
          }
        }
      }

      // 弹出表单对话框
      const formData = await showSchemaFormDialog({
        formSchema: {},
        schema: {},
        initialValues,
        title: '修改数据点',
        description: `请填写要修改的数据点值`,
      })

      // 用户取消操作
      if (!formData) {
        return { success: true, data: { dataPointMulti, cancelled: true } }
      }

      // 构建表单值数组
      const formValues = dataPointMulti.map(dp => formData[dp.key])

      // 更新数据点
      const results: any[] = []
      for (let i = 0; i < dataPointMulti.length; i++) {
        const dp = dataPointMulti[i]
        const pointValue = formValues[i]

        if (dp.recordDataPoint) {
          // 资产数据点
          await updateRecordDataPoint(dp, pointValue)
          results.push({ type: 'record', recordDataPoint: dp.recordDataPoint, value: pointValue })
        } else if (dp.tableDataPoint) {
          // 模型数据点
          await updateTableDataPoint(dp, pointValue)
          results.push({ type: 'table', tableDataPoint: dp.tableDataPoint, value: pointValue })
        } else {
          throw new Error(`数据点配置错误：既没有 recordDataPoint 也没有 tableDataPoint`)
        }
      }

      showResultMessage({ success: true }, params)

      return { success: true, data: { results } }
    } else {
      // 直接修改模式 - 使用每个元素内部的 value
      const results: any[] = []

      // 遍历所有数据点进行更新
      for (const dp of dataPointMulti) {
        const pointValue = dp.value

        if (dp.recordDataPoint) {
          // 资产数据点
          await updateRecordDataPoint(dp, pointValue)
          results.push({ type: 'record', recordDataPoint: dp.recordDataPoint, value: pointValue })
        } else if (dp.tableDataPoint) {
          // 模型数据点
          await updateTableDataPoint(dp, pointValue)
          results.push({ type: 'table', tableDataPoint: dp.tableDataPoint, value: pointValue })
        } else {
          throw new Error(`数据点配置错误：既没有 recordDataPoint 也没有 tableDataPoint`)
        }
      }

      showResultMessage({ success: true }, params)

      return { success: true, data: { results } }
    }
  } catch (error) {
    const result: ActionResult = {
      success: false,
      error: error instanceof Error ? error.message : '修改数据点配置失败',
    }
    showResultMessage(result, params)
    return result
  }
}

/**
 * 事件和动作类型定义
 */

/** 事件类型 */
export type EventType =
  | 'click' // 单击
  | 'doubleClick' // 双击
  | 'mouseEnter' // 移入
  | 'mouseLeave' // 移出
  | 'change' // 值变化
  | 'submit' // 表单提交
  | 'focus' // 聚焦
  | 'blur' // 失焦
  | 'input' // 输入

/** 动作类型 */
export type ActionType =
  | 'pageJump' // 页面跳转
  | 'changeVar' // 修改变量
  | 'changeTableData' // 修改表数据
  | 'changeDict' // 修改数据字典
  | 'changeDataPoint' // 修改数据点配置
  | 'changeSystemSetting' // 修改系统设置
  | 'changeUser' // 修改用户
  | 'callFlow' // 调用流程
  | 'executeCommand' // 执行指令
  | 'sendRequest' // 发送请求

/** 值类型 - 变量值或组件值 */
export type ValueType = 'varValue' | 'comValue'

/** 执行结果消息配置 */
export interface ResultMessage {
  /** 成功提示 */
  successMess?: boolean
  /** 成功显示时常（秒） */
  successTime?: number
  /** 成功显示内容 */
  successContent?: string
  /** 失败提示 */
  errorMess?: boolean
  /** 失败显示时常（秒） */
  errorTime?: number
  /** 失败显示内容 */
  errorContent?: string
}

/** 打开方式 */
export type OpenWay = '_blank' | '_self' | '_parent' | '_top'

/** 权限类型 */
export type PermissionType = 'users' | 'roles'

/** 页面跳转动作参数 */
export interface PageJumpParams {
  url: string
  openWay?: OpenWay
  showMessage?: boolean
  permission?: PermissionType
  users?: string[]
  roles?: string[]
}

/** 修改变量动作参数 */
export interface ChangeVarParams extends ResultMessage {
  var: Record<string, any>
  varValue?: Record<string, any>
}

/** 修改表数据动作参数 */
export interface ChangeTableDataParams extends ResultMessage {
  table: Record<string, any>
  data: Record<string, any>
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: Array<{
    key: string
    value: string
  }>
}

/** 修改数据字典动作参数 */
export interface ChangeDictParams extends ResultMessage {
  systemVar: Record<string, any>
  value?: Record<string, any>
}

/** 数据点属性 */
export interface DataPointProperty {
  /** 资产数据点 */
  recordDataPoint?: {
    tableId: string
    tableDataId: string
    tagId: string
  }
  /** 模型数据点 */
  tableDataPoint?: {
    tableId: string
    tagId: string
  }
  /** 要更新的属性键 */
  key: string
  /** 要设置的值 */
  value?: any
}

/** 修改数据点配置动作参数 */
export interface ChangeDataPointParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  /** 数据点配置数组 */
  dataPointMulti: DataPointProperty[]
}

/** 字段和值 */
export interface FieldValuePair {
  key: string
  value: string
}

/** 修改系统设置动作参数 */
export interface ChangeSystemSettingParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: FieldValuePair[]
}

/** 修改用户动作参数 */
export interface ChangeUserParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: FieldValuePair[]
}

/** 调用流程动作参数 */
export interface CallFlowParams extends ResultMessage {
  flow: Record<string, any>
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  params?: Record<string, any>
}

/** 动作基础接口 */
export interface Action {
  /** 动作类型 */
  type: ActionType
  /** 动作参数 */
  params: any
  /** 是否需要二次确认 */
  confirm?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
  /** 延迟执行（毫秒） */
  delay?: number
}

/** 事件配置 */
export interface EventConfig {
  [eventType: string]: Action[]
}

/** 事件函数集合 */
export interface EventFunctions {
  /** 设置页面变量 */
  setPageVar?: (path: string, value: any) => void
}

/** 事件执行上下文 */
export interface EventContext {
  /** 事件源组件 */
  component?: React.ComponentType<any>
  /** 当前事件类型 */
  eventType: EventType
  /** 事件触发参数（如事件对象） */
  eventParams?: any
  /** 前一个动作的执行结果 */
  prevResult?: any
  /** 事件函数集合 */
  eventFunctions?: EventFunctions
}

/** 动作执行结果 */
export interface ActionResult {
  /** 是否成功 */
  success: boolean
  /** 返回数据 */
  data?: any
  /** 错误信息 */
  error?: string
}

/** 动作处理器 */
export type ActionHandler = (
  params: any,
  context: EventContext
) => Promise<ActionResult> | ActionResult

/** 事件处理器返回值 */
export interface EventHandlerReturn {
  /** 事件处理函数 */
  handler: (e?: React.SyntheticEvent) => void | Promise<void>
  /** 是否正在执行 */
  loading: boolean
  /** 执行错误 */
  error: string | null
}

/** 事件配置对象 */
export interface EventsReturn extends Partial<Record<EventType, (e?: React.SyntheticEvent) => void | Promise<void>>> {
  /** 各事件的处理器 */
  [key: string]: ((e?: React.SyntheticEvent) => void | Promise<void>) | EventConfig | undefined
  /** 事件配置原始数据 */
  config: EventConfig
}

/**
 * 统一的对话框状态管理
 *
 * 使用方式：
 * 1. 显示对话框：await showConfirmDialog(config)
 * 2. 手动关闭：closeConfirmDialog()
 * 3. 全局组件：<GlobalDialogs />
 */

import { atom, createStore, useAtom, useSetAtom } from 'jotai'

// 创建全局 store
const dialogStore = createStore()

// 创建 atoms
export const confirmDialogAtom = atom<{
  open: boolean
  resolve?: (value: boolean) => void
  config?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
} | null>(null)

export const formDialogAtom = atom<{
  open: boolean
  resolve?: (value: any) => void
  config?: {
    title?: string
    description?: string
    fields?: any[]
    confirmText?: string
    cancelText?: string
    initialValues?: Record<string, any>
  }
} | null>(null)

/** SchemaForm 对话框 atom */
export const schemaFormDialogAtom = atom<{
  open: boolean
  resolve?: (value: any) => void
  config?: {
    title?: string
    description?: string
    schema?: any
    formSchema?: any
    confirmText?: string
    cancelText?: string
    initialValues?: Record<string, any>
  }
} | null>(null)

// 显示确认对话框
export function showConfirmDialog(
  config?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
): Promise<boolean> {
  return new Promise((resolve) => {
    // 使用 store.set 设置 atom 值
    dialogStore.set(confirmDialogAtom, {
      open: true,
      resolve,
      config,
    })
  })
}

// 关闭确认对话框
export function closeConfirmDialog() {
  dialogStore.set(confirmDialogAtom, null)
}

// 显示表单对话框
export function showFormDialog(
  fields: any[],
  initialValues?: Record<string, any>,
  title?: string,
  description?: string
): Promise<Record<string, any> | null> {
  return new Promise((resolve) => {
    dialogStore.set(formDialogAtom, {
      open: true,
      resolve,
      config: {
        title,
        description,
        fields,
        confirmText: '确定',
        cancelText: '取消',
        initialValues,
      },
    })
  })
}

// 关闭表单对话框
export function closeFormDialog() {
  dialogStore.set(formDialogAtom, null)
}

// 显示 SchemaForm 对话框
export function showSchemaFormDialog(
  config?: {
    schema?: any
    initialValues?: Record<string, any>
    title?: string
    description?: string
    formSchema?: any
  }
): Promise<Record<string, any> | null> {
  return new Promise((resolve) => {
    dialogStore.set(schemaFormDialogAtom, {
      open: true,
      resolve,
      config: {
        title: config?.title,
        description: config?.description,
        schema: config?.schema,
        formSchema: config?.formSchema,
        confirmText: '确定',
        cancelText: '取消',
        initialValues: config?.initialValues,
      },
    })
  })
}

// 关闭 SchemaForm 对话框
export function closeSchemaFormDialog() {
  dialogStore.set(schemaFormDialogAtom, null)
}

// 组件使用的 hook
export function useGlobalDialogs() {
  // 指定使用 dialogStore
  const [confirmDialog] = useAtom(confirmDialogAtom, { store: dialogStore })
  const [formDialog] = useAtom(formDialogAtom, { store: dialogStore })
  const [schemaFormDialog] = useAtom(schemaFormDialogAtom, { store: dialogStore })
  const setConfirmDialog = useSetAtom(confirmDialogAtom, { store: dialogStore })
  const setFormDialog = useSetAtom(formDialogAtom, { store: dialogStore })
  const setSchemaFormDialog = useSetAtom(schemaFormDialogAtom, { store: dialogStore })

  // 处理确认对话框的确认
  const handleConfirm = () => {
    if (confirmDialog?.resolve) {
      confirmDialog.resolve(true)
      setConfirmDialog(null)
    }
  }

  // 处理确认对话框的取消
  const handleCancel = () => {
    if (confirmDialog?.resolve) {
      confirmDialog.resolve(false)
      setConfirmDialog(null)
    }
  }

  // 处理表单对话框的确认
  const handleFormConfirm = (data: any) => {
    if (formDialog?.resolve) {
      formDialog.resolve(data)
      setFormDialog(null)
    }
  }

  // 处理表单对话框的取消
  const handleFormCancel = () => {
    if (formDialog?.resolve) {
      formDialog.resolve(null)
      setFormDialog(null)
    }
  }

  // 处理 SchemaForm 对话框的确认
  const handleSchemaFormConfirm = (data: any) => {
    if (schemaFormDialog?.resolve) {
      schemaFormDialog.resolve(data)
      setSchemaFormDialog(null)
    }
  }

  // 处理 SchemaForm 对话框的取消
  const handleSchemaFormCancel = () => {
    if (schemaFormDialog?.resolve) {
      schemaFormDialog.resolve(null)
      setSchemaFormDialog(null)
    }
  }

  return {
    confirmDialog,
    formDialog,
    schemaFormDialog,
    handleConfirm,
    handleCancel,
    handleFormConfirm,
    handleFormCancel,
    handleSchemaFormConfirm,
    handleSchemaFormCancel,
  }
}

/**
 * Handler 工具函数
 */

import type {
  ActionResult,
  ResultMessage,
} from '../events.types'
import { toast } from 'sonner'

/**
 * 显示执行结果消息
 */
export function showResultMessage(
  result: ActionResult,
  resultConfig?: ResultMessage
) {
  if (!resultConfig) return

  if (result.success) {
    if (resultConfig.successMess !== false) {
      toast.success(resultConfig.successContent || '操作成功', {
        duration: resultConfig.successTime || 3000,
      })
    }
  } else {
    if (resultConfig.errorMess !== false) {
      toast.error(resultConfig.errorContent || result.error || '操作失败', {
        duration: resultConfig.errorTime || 3000,
      })
    }
  }
}
